-- ── Microweber ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Microweber is an open-source, Laravel-based CMS and website builder that lets users edit pages live via drag-and-drop, with built-in ecommerce and blogging tools.$q$, short_description),
  pricing_model = COALESCE($q$Open Source / Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted, open source)$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$Small team/startup$q$, company_size),
  headquarters = COALESCE($q$Sofia, Bulgaria$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Microweber Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Microweber review 2026: open-source drag-and-drop CMS pricing, ecommerce features, and how it compares to WordPress, Wix and Shopify.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Microweber is an open-source content management system (CMS) and website builder that combines a live drag-and-drop visual editor with an underlying Laravel PHP framework. Development began around 2010 in Sofia, Bulgaria, by a small team of web developers, including Peter Ivanov, Boris Sokolov, Alex Raikov, and Borislav Iordanov, who ran a web-design agency and found existing CMS platforms too complex for everyday users and clients. The project's first stable 1.0.0 release shipped on February 16, 2015, built on the Laravel 5 framework, and the company behind it is headquartered in Sofia, Bulgaria. In 2018, with version 1.1.0, Microweber switched its license from GPL to MIT, making it more permissive for commercial and open-source reuse; the project has since been recognized as one of Bulgaria's notable startups. Unlike traditional CMSs that separate a back-end admin panel from a front-end preview, Microweber lets users edit content directly on the live page, dragging in modules (text, images, galleries, forms, shop products) and editing text inline, similar to a page builder like Elementor or Webflow but built into the CMS core rather than as a plugin. It ships with built-in ecommerce functionality (product catalogs, cart, checkout, payment gateway integration via Omnipay), blogging, a template and theme marketplace, and a REST API and module system for developers to extend functionality. Because it is Laravel-based and open source, it can be self-hosted for free on any PHP/MySQL-compatible server, and its source code is available on GitHub under the MIT license. Commercially, Microweber offers a dual model: the core CMS is free to download and self-host, while Microweber.com (and microweber.org) also sell managed cloud-hosted plans aimed at non-technical users and small businesses, bundling hosting, storage, and site/page limits into tiered monthly plans, plus an Enterprise and reseller license for hosting companies and agencies that want to white-label Microweber as a SaaS product. Its target audience spans hobbyists and freelancers who want a free self-hosted site builder, small businesses and agencies wanting an all-in-one hosted website-plus-shop solution, and developers who prefer a Laravel-based, code-extensible CMS over WordPress's PHP and plugin architecture. Its main competitors include WordPress (with Elementor and WooCommerce), Wix, Shopify, and Webflow; Microweber's key differentiator is being fully open source and self-hostable while still offering the live-editing, drag-and-drop experience typically associated with proprietary closed SaaS builders.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'aa18bfe8-dba3-4e07-9d0c-7fd408d29121';

