-- ── middlewarehq ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$middlewarehq is an open-source, self-hostable platform that calculates DORA metrics, deployment frequency, lead time, change failure rate, and mean time to restore, from an engineering team's Git and CI/CD data.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted, open source)$q$, starting_price),
  founded_year = COALESCE(2022, founded_year),
  company_size = COALESCE($q$Small startup (seed-funded)$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$middlewarehq Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$middlewarehq review 2026: open-source DORA metrics platform pricing, GitHub integration, self-hosting, and alternatives like LinearB and Jellyfish.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$middlewarehq (published as the open-source project at github.com/middlewarehq/middleware, also referenced as the dora-metrics repository) is a self-hosted engineering-metrics platform that computes the four DORA (DevOps Research and Assessment) metrics, deployment frequency, lead time for changes, mean time to restore, and change failure rate, directly from a team's version-control and CI/CD data. It is built and maintained by Middleware, a company founded by Laduram Vishnoi (previously founder of the customer-support platform Acquire) in late 2022, initially funded with a $500,000 personal investment before the company raised a $6.5 to $7 million seed round led by 8VC, with participation from Fin Capital, Vercel CEO Guillermo Rauch, and other angels. Middleware went through Y Combinator's Winter 2023 batch and is headquartered in San Francisco, California. Middleware's commercial product is a broader AI-based cloud and full-stack observability platform, but middlewarehq is its dedicated open-source DORA metrics tool, released under the Apache 2.0 license and written primarily in TypeScript. It is designed to be deployed via Docker, either self-hosted on a company's own infrastructure or, in the commercial version, offered as a hosted SaaS product. The core technical approach is to pull data from Git hosting providers (GitHub being the primary supported source, with the project's stated goal of eventually supporting metrics from git data regardless of other integrations) and CI/CD pipelines, then compute and visualize the four DORA metrics on dashboards that let engineering leaders benchmark their team's software delivery performance against the industry-standard DORA performance tiers of Elite, High, Medium, and Low. middlewarehq's target audience is engineering leaders, VPs of Engineering, and platform and DevOps teams who want objective, automatically computed delivery performance metrics without manually assembling spreadsheets from Jira and Git logs, and who prefer, or require for security and compliance reasons, a self-hostable open-source tool over a fully managed third-party SaaS. Its main competitors include LinearB, Jellyfish, Swarmia, Faros AI, Sleuth, and GitClear, most of which are closed-source commercial SaaS products; Google's own DORA research popularized the four metrics that all of these tools compute. middlewarehq's key differentiator is being free, open-source, and self-hostable, which appeals to engineering organizations wary of sending source-control metadata to a third-party SaaS vendor, while its parent company also offers a commercial hosted and managed version and broader observability tooling for teams that want a fully managed solution.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '5017ecef-eeac-41d4-87fc-cca911bb4e30';

