-- ── Midjourney ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Midjourney is a self-funded AI research lab and image-generation service that turns text prompts into high-quality AI-generated images and video, accessed via Discord and its own web app.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$10/month (Basic Plan)$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE($q$Small team (self-funded, reportedly well under a few hundred employees)$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Midjourney Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Midjourney review 2026: V7/V8 features, pricing plans from $10 to $120 per month, Discord vs web app, and how it compares to DALL-E and Stable Diffusion.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Midjourney is an independent AI research lab and product that generates images, and increasingly video, from text prompts using proprietary diffusion-based generative models. It was founded in August 2021 in San Francisco by David Holz, a former NASA researcher who had previously co-founded and led the hand-tracking hardware company Leap Motion. Midjourney entered open beta on July 12, 2022, and became one of the breakout consumer AI products of the 2022-2023 generative AI boom alongside OpenAI's DALL-E and Stability AI's Stable Diffusion. Unusually for a frontier AI company, Midjourney has never raised institutional venture capital and remains entirely self-funded and profitable, reportedly reaching around $300 million in revenue in fiscal 2024 according to PitchBook estimates, while operating with a comparatively small team. Midjourney's product is delivered primarily through Discord, where users issue '/imagine' commands with text prompts in official Midjourney Discord servers or their own servers via the Midjourney bot, as well as through a standalone web application (midjourney.com) that provides a more traditional prompt box, image gallery, and editing interface. Core capabilities include text-to-image generation, image variation and upscaling, image-to-image and style-reference blending, in-painting and editing, and, with newer model versions, short AI video generation. The company has iterated through numbered model versions (V4 through V7), with V7 bringing improved prompt coherence and image quality, and V8 Alpha, introduced around March 2026, adding native 2K resolution output, sharper text rendering within images, and roughly 5x faster generation than prior versions. Midjourney is sold on a subscription basis with four consumer and prosumer tiers: Basic ($10/month), Standard ($30/month), Pro ($60/month), and Mega ($120/month), each granting a different allotment of 'Fast' GPU generation minutes plus unlimited slower 'Relax' mode generations on Standard tier and above; annual billing carries roughly a 20 percent discount versus monthly. There is no longer a free tier for new users. In August 2025, Midjourney announced a strategic technology partnership with Meta to license its aesthetic and image-generation technology for use in future Meta AI products, an unusual deal for a company that has otherwise avoided outside investment or big-tech ownership stakes. Midjourney's target audience spans digital artists, illustrators, concept artists, marketers, and hobbyists who want high aesthetic-quality AI imagery, as well as increasingly game studios, ad agencies, and product-design teams. Its main competitors are OpenAI's DALL-E and GPT image generation, Stability AI's Stable Diffusion (and Stable Diffusion-based tools like Leonardo.Ai), Adobe Firefly, and Google's Imagen and Gemini image tools. Midjourney's key differentiators are its distinctive, widely praised aesthetic output quality, its self-funded independence from big-tech platform constraints, and its community-driven Discord-native workflow, though the web app has narrowed the gap for users who prefer a conventional SaaS interface over Discord.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '99710d40-9738-45f6-85cf-44868ba8a012';

