-- ── Milvus ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Milvus is an open-source, distributed vector database built for storing and searching billions of high-dimensional embeddings, used for AI applications like semantic search, RAG, and recommendation systems.$q$, short_description),
  pricing_model = COALESCE($q$Open Source / Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (open source, self-hosted); Zilliz Cloud from a free tier or roughly $99/month for dedicated clusters$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$Zilliz: mid-size startup, $113M+ total funding$q$, company_size),
  headquarters = COALESCE($q$Redwood City, California, United States (Zilliz)$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Chinese$q$]::text[],
  seo_title = COALESCE($q$Milvus Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Milvus review 2026: open-source vector database features, Zilliz Cloud pricing, RAG and AI search use cases, and how it compares to Pinecone and Weaviate.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Milvus is an open-source, distributed vector database purpose-built for storing, indexing, and searching billions of high-dimensional embedding vectors, the numerical representations used by modern AI systems for semantic search, retrieval-augmented generation (RAG), recommendation engines, and image and video similarity search. Milvus was originally developed starting in 2018 by Zilliz, a company founded in 2017 and headquartered in Redwood City, California, and was open-sourced in 2019. In 2020, Zilliz donated Milvus to the Linux Foundation's LF AI and Data Foundation, making it a vendor-neutral, community-governed open-source project rather than a purely Zilliz-controlled codebase, though Zilliz remains the primary corporate steward and largest contributor. Milvus is released under the Apache 2.0 license and has become the most widely adopted open-source vector database, with more than 42,000 GitHub stars. Technically, Milvus is designed as a cloud-native, horizontally scalable system that separates storage and compute, supports multiple approximate-nearest-neighbor (ANN) indexing algorithms (including HNSW, IVF, and DiskANN), and can run as a lightweight single-node deployment (Milvus Lite, embedded in a Python process), a standalone Docker deployment for small-to-medium workloads, or a fully distributed Kubernetes-based cluster (Milvus Cluster) for massive-scale production workloads spanning billions of vectors. It integrates with popular AI and ML frameworks and orchestration libraries such as LangChain, LlamaIndex, and Hugging Face, and supports hybrid search combining vector similarity with traditional scalar and metadata filtering. Zilliz funds Milvus's development and monetizes it primarily through Zilliz Cloud, a fully managed, hosted version of Milvus. Zilliz has raised roughly $113 million across three funding rounds, including a $43 million Series B in November 2020 led by Hillhouse Capital and a further $60 million round in August 2022 led by Prosperity7 Ventures, alongside earlier funding from Yunqi Partners and 5Y Capital. Zilliz Cloud pricing includes a free tier (roughly 5GB storage and 2.5 million vCUs per month), a pay-as-you-go Serverless tier (around $4 per million vCUs), and Dedicated cluster tiers starting around $99/month, with a 30-day free trial on paid tiers. The self-hosted, open-source version of Milvus remains completely free to run on a company's own infrastructure. Milvus's target audience is AI and ML engineering teams building semantic search, RAG pipelines for large language model applications, recommendation systems, and computer-vision similarity search, ranging from individual developers running Milvus Lite locally to large enterprises running distributed Milvus clusters or Zilliz Cloud. Its main competitors are Pinecone (fully managed, closed-source), Weaviate, Qdrant, Chroma, and pgvector (a PostgreSQL extension); Milvus differentiates itself through its open-source, vendor-neutral governance under the Linux Foundation, proven large-scale distributed architecture, and the option to move between self-hosted open source and Zilliz's managed cloud without changing databases.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f8173937-6906-403b-af26-bf7290c0ba12';

