INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c0078b68-a3db-4bd7-a30e-97b858ae7f1e', $q$Enterprise portfolio features require add-on licensing and setup complexity$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c0078b68-a3db-4bd7-a30e-97b858ae7f1e', $q$Is Microsoft Project part of Microsoft 365?$q$, $q$It is sold separately as add-on subscription plans rather than included in standard Microsoft 365 Business or Enterprise plans, though it shares the same billing and admin infrastructure.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c0078b68-a3db-4bd7-a30e-97b858ae7f1e', $q$Does Microsoft Project have a free version?$q$, $q$There is no permanent free tier, but Microsoft offers a 30-day free trial on its paid plans.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c0078b68-a3db-4bd7-a30e-97b858ae7f1e', $q$What is the difference between Microsoft Project and Microsoft Planner?$q$, $q$Planner is a lightweight task and Kanban tool, while Project is for formal scheduling with Gantt charts, dependencies, and resource leveling; Microsoft has merged both into a unified Planner app experience with Project plans layered on top.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c0078b68-a3db-4bd7-a30e-97b858ae7f1e', $q$Can Microsoft Project be used on Mac?$q$, $q$The web-based Project for the web works in any browser, but the full desktop Project client is Windows only.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c0078b68-a3db-4bd7-a30e-97b858ae7f1e', $q$What file format does Microsoft Project use?$q$, $q$.mpp, a proprietary format widely supported by import and export tools in competing project management software.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c0078b68-a3db-4bd7-a30e-97b858ae7f1e', $q$Who is Microsoft Project best suited for?$q$, $q$Mid-size and enterprise teams with formal scheduling needs, especially organizations already standardized on Microsoft 365.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c0078b68-a3db-4bd7-a30e-97b858ae7f1e', $q$Enterprise PMO portfolio management$q$, $q$Prioritize, sequence, and optimize a portfolio of competing projects with demand management and capacity tools.$q$, $q$PMO leaders and enterprise program managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c0078b68-a3db-4bd7-a30e-97b858ae7f1e', $q$Construction and engineering scheduling$q$, $q$Track detailed task dependencies, critical paths, and resource costs on large builds.$q$, $q$Construction and engineering project managers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c0078b68-a3db-4bd7-a30e-97b858ae7f1e', $q$IT and software delivery scheduling$q$, $q$Coordinate cross-functional IT project timelines alongside Teams and SharePoint.$q$, $q$IT project managers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c0078b68-a3db-4bd7-a30e-97b858ae7f1e', $q$Project Plan 1$q$, $q$$10/user/month$q$, $q$Monthly or annual$q$, NULL, $q$["Web-based grid, board, and timeline views","Basic task management","Co-authoring"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c0078b68-a3db-4bd7-a30e-97b858ae7f1e', $q$Project Plan 3$q$, $q$$30/user/month$q$, $q$Monthly or annual$q$, NULL, $q$["Desktop client","Resource management","Timesheets and reporting"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c0078b68-a3db-4bd7-a30e-97b858ae7f1e', $q$Project Plan 5$q$, $q$$55/user/month$q$, $q$Monthly or annual$q$, NULL, $q$["Portfolio and demand management","Enterprise resource planning","Capacity heat maps"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c0078b68-a3db-4bd7-a30e-97b858ae7f1e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Microsoft Project is Microsoft's dedicated project and portfolio management application, first released in 1984 and now sold as a set of subscription plans (Project Plan 1, 3, and 5) alongside Microsoft Planner. It is built for detailed scheduling, budgeting, and resource management rather than lightweight task tracking, and integrates with the wider Microsoft 365 ecosystem including Teams, SharePoint, and Power BI.$q$, $q$The product spans a browser-based experience for grid, board, and timeline views, an optional Windows desktop client for advanced Gantt-chart scheduling and critical-path analysis, and enterprise portfolio management tools for organizations juggling many concurrent projects. It remains a standard tool in construction, engineering, IT, and government project management.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c0078b68-a3db-4bd7-a30e-97b858ae7f1e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At the center of Microsoft Project is Gantt-chart scheduling with task dependencies, critical path calculation, and baseline tracking, which lets project managers see exactly how a schedule slip in one task cascades through a plan. Resource management tools allow leveling workloads across people and tracking cost against budget.$q$, $q$Higher tiers add timesheets, enterprise resource planning, and portfolio-level dashboards that help PMOs compare, prioritize, and optimize competing projects. Native Power BI connectors turn raw project data into executive-ready reporting, and Teams integration keeps project conversations and files attached to the plan.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c0078b68-a3db-4bd7-a30e-97b858ae7f1e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Microsoft Project pricing is structured into three subscription tiers: Project Plan 1 at $10/user/month for web-based task and timeline tracking, Project Plan 3 at $30/user/month adding the desktop client and resource management, and Project Plan 5 at $55/user/month for full enterprise portfolio and demand management.$q$, $q$There is no permanent free tier, though Microsoft offers a 30-day free trial. Because pricing is per user per month, costs scale directly with team size, and organizations typically mix tiers, assigning Plan 5 only to PMO staff who need portfolio tools while giving individual contributors cheaper Plan 1 seats.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$Team chat and channels$q$, $q$Threaded, topic-organized conversations with mentions and reactions.$q$, 0);
