INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$Is Microsoft Teams free?$q$, $q$Yes, a free tier exists with unlimited chat and meetings up to 60 minutes for up to 100 participants.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$What is the cheapest paid plan?$q$, $q$Teams Essentials at $4/user/month.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$Do I need Microsoft 365 to use Teams?$q$, $q$No, Teams Essentials works standalone, but most advanced features come bundled with Microsoft 365 plans.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$Does Teams replace Skype for Business?$q$, $q$Yes, Microsoft retired Skype for Business in favor of Teams.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$Can external guests join Teams meetings?$q$, $q$Yes, guest access and shared channels support external collaboration.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$What is Teams Phone?$q$, $q$An add-on that turns Teams into a cloud PBX/VoIP phone system with PSTN calling.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$Company-wide team communication$q$, $q$Centralize chat, files, and meetings for an entire organization.$q$, $q$SMB and enterprise IT departments$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$Hybrid meetings and webinars$q$, $q$Host internal meetings and larger external webinars with screen sharing and recording.$q$, $q$Sales, marketing, and HR teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$Frontline worker shift coordination$q$, $q$Coordinate shifts, tasks, and announcements for distributed frontline staff.$q$, $q$Retail and healthcare frontline teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited chat","60-minute meetings up to 100 participants","5GB storage"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$Teams Essentials$q$, $q$$4/user/month$q$, $q$Monthly or annual$q$, NULL, $q$["30-hour meetings","Up to 300 participants","10GB storage"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$Microsoft 365 Business Basic$q$, $q$From $6/user/month$q$, $q$Monthly or annual$q$, NULL, $q$["Teams plus web and mobile Office apps","1TB storage"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$Microsoft 365 E3/E5$q$, $q$Roughly $39-$60/user/month$q$, $q$Annual$q$, NULL, $q$["Teams Phone","Advanced security and compliance","Full desktop Office apps"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Microsoft Teams is Microsoft's chat-and-meetings collaboration hub, launched in March 2017 as the company's response to Slack and the eventual replacement for Skype for Business. It combines persistent channel-based messaging, video and audio meetings, and file co-authoring into a single application tied to the Microsoft 365 ecosystem.$q$, $q$Each Team is backed by a Microsoft 365 Group with a SharePoint document library, shared OneNote notebook, and Exchange calendar integration, which is why Teams feels less like a standalone chat app and more like a front end for the rest of Office. Teams now reports well over 300 million monthly active users.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Teams' core is channel-based team chat with threaded conversations, @mentions, and an app store offering thousands of tab and bot integrations, from Planner to third-party tools like Asana or Salesforce. Meetings support screen sharing, breakout rooms, together mode, and built-in whiteboarding.$q$, $q$Copilot AI features layered on top of Teams can summarize meetings, generate follow-up action items, and answer questions about chat history. Teams Phone, an add-on available at higher tiers, turns Teams into a cloud PBX capable of PSTN calling, replacing traditional desk phone systems.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Teams has a free tier with 5GB of storage and meetings capped at 60 minutes for up to 100 participants, which is enough for many small teams. Teams Essentials, at $4/user/month, is the cheapest paid tier and the only way to buy Teams without a full Microsoft 365 subscription, extending meetings to 30 hours and 300 participants.$q$, $q$Beyond Essentials, Teams is bundled into Microsoft 365 Business Basic, Standard, and Premium plans, and into Enterprise E3/E5 licenses, which add the full Office application suite, larger storage, and (at higher tiers) Teams Phone and advanced compliance features. Microsoft 365 and Teams pricing increased in 2026, with enterprise tiers now spanning roughly $39 to $60 per user per month.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa18bfe8-dba3-4e07-9d0c-7fd408d29121', $q$Live drag-and-drop editing$q$, $q$Edit content directly on the live page rather than in a separate admin preview.$q$, 0);
