INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa18bfe8-dba3-4e07-9d0c-7fd408d29121', $q$What is Microweber built on?$q$, $q$The Laravel PHP framework.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa18bfe8-dba3-4e07-9d0c-7fd408d29121', $q$Does Microweber support ecommerce?$q$, $q$Yes, it has built-in shop, cart, and payment gateway features via Omnipay.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa18bfe8-dba3-4e07-9d0c-7fd408d29121', $q$How is Microweber different from WordPress?$q$, $q$Microweber uses live, on-page drag-and-drop editing built into the CMS core rather than a separate builder plugin, and is Laravel-based rather than WordPress's custom PHP architecture.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa18bfe8-dba3-4e07-9d0c-7fd408d29121', $q$Can agencies white-label Microweber?$q$, $q$Yes, an Enterprise and reseller license lets hosting companies offer Microweber as a branded SaaS product.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa18bfe8-dba3-4e07-9d0c-7fd408d29121', $q$Where is Microweber based?$q$, $q$Sofia, Bulgaria.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('aa18bfe8-dba3-4e07-9d0c-7fd408d29121', $q$Small business website and online shop$q$, $q$Build a marketing site plus an integrated ecommerce store in one install.$q$, $q$Small business owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('aa18bfe8-dba3-4e07-9d0c-7fd408d29121', $q$Agency white-label website builder$q$, $q$Resell a branded website-building platform to clients under Enterprise licensing.$q$, $q$Web agencies and hosting companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('aa18bfe8-dba3-4e07-9d0c-7fd408d29121', $q$Developer-customized CMS projects$q$, $q$Extend the open-source Laravel codebase with custom modules and integrations.$q$, $q$PHP and Laravel developers$q$, 2);
