INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('aa18bfe8-dba3-4e07-9d0c-7fd408d29121', $q$Cloud Individual$q$, $q$Paid monthly$q$, $q$Monthly$q$, NULL, $q$["1 website","Limited pages","500MB storage"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('aa18bfe8-dba3-4e07-9d0c-7fd408d29121', $q$Cloud Professional$q$, $q$Paid monthly$q$, $q$Monthly$q$, NULL, $q$["Up to 5 websites","Unlimited pages","5GB storage"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('aa18bfe8-dba3-4e07-9d0c-7fd408d29121', $q$Cloud Agency$q$, $q$Paid monthly$q$, $q$Monthly$q$, NULL, $q$["Up to 10 websites","Unlimited pages","20GB storage"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('aa18bfe8-dba3-4e07-9d0c-7fd408d29121', $q$Enterprise/Reseller$q$, $q$Custom pricing$q$, $q$Custom$q$, NULL, $q$["White-label SaaS licensing for hosting companies"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('aa18bfe8-dba3-4e07-9d0c-7fd408d29121', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Microweber is an open-source CMS and website builder that grew out of a Sofia, Bulgaria web-design agency's frustration with existing CMS platforms being too complicated for everyday clients. Built on the Laravel PHP framework, its first stable release shipped in February 2015, and the project switched to the permissive MIT license in 2018.$q$, $q$What sets Microweber apart from a typical CMS is that editing happens directly on the live page rather than in a separate admin preview; users drag modules like text, images, and shop products straight onto the page and edit them inline, closer to a page-builder experience than a traditional back-end CMS.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('aa18bfe8-dba3-4e07-9d0c-7fd408d29121', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Microweber ships with a built-in ecommerce module (product catalog, cart, checkout, and Omnipay payment gateway integration), blogging tools, and a marketplace of templates and modules, so a single install can cover a marketing site, blog, and online shop without extra plugins.$q$, $q$Because the codebase is open source and Laravel-based, developers can extend it with custom modules and a REST API, and anyone can self-host it for free on a standard PHP/MySQL server. Microweber.com and microweber.org also sell managed cloud hosting for users who don't want to manage a server themselves.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('aa18bfe8-dba3-4e07-9d0c-7fd408d29121', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The core Microweber CMS is free and open source, and can be downloaded from GitHub and self-hosted at no cost beyond hosting infrastructure. For users who want a managed experience, Microweber.com sells tiered cloud plans that bundle hosting, storage, and website/page limits, scaling from single-site individual plans up to multi-site agency plans.$q$, $q$An Enterprise and reseller license is also available for hosting companies and agencies that want to offer Microweber as a white-labeled SaaS product under their own brand, positioning Microweber as both a free developer tool and a commercial hosted product depending on the customer's needs.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('aa18bfe8-dba3-4e07-9d0c-7fd408d29121', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
