INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5017ecef-eeac-41d4-87fc-cca911bb4e30', $q$Is middlewarehq free?$q$, $q$Yes, the core project is open source under the Apache 2.0 license and free to self-host.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5017ecef-eeac-41d4-87fc-cca911bb4e30', $q$Who makes middlewarehq?$q$, $q$Middleware, a Y Combinator (W23) and 8VC-backed startup founded by Laduram Vishnoi.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5017ecef-eeac-41d4-87fc-cca911bb4e30', $q$What are DORA metrics?$q$, $q$Four metrics from DevOps Research and Assessment: deployment frequency, lead time for changes, mean time to restore, and change failure rate.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5017ecef-eeac-41d4-87fc-cca911bb4e30', $q$How is middlewarehq deployed?$q$, $q$Via Docker, either self-hosted or as a managed cloud offering from Middleware.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5017ecef-eeac-41d4-87fc-cca911bb4e30', $q$Which Git providers does middlewarehq support?$q$, $q$GitHub is the primary supported source, with broader Git data support as a stated project goal.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5017ecef-eeac-41d4-87fc-cca911bb4e30', $q$Who is middlewarehq for?$q$, $q$Engineering leaders and DevOps or platform teams wanting objective software delivery performance metrics.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5017ecef-eeac-41d4-87fc-cca911bb4e30', $q$Engineering leadership benchmarking$q$, $q$Track and benchmark software delivery performance against DORA tiers.$q$, $q$VPs of Engineering and CTOs$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5017ecef-eeac-41d4-87fc-cca911bb4e30', $q$Self-hosted metrics for security-conscious orgs$q$, $q$Run the full metrics stack in-house without sending data to a third party.$q$, $q$Regulated and enterprise engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5017ecef-eeac-41d4-87fc-cca911bb4e30', $q$DevOps process improvement tracking$q$, $q$Identify delivery bottlenecks and measure the impact of process changes over time.$q$, $q$Platform and DevOps engineers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5017ecef-eeac-41d4-87fc-cca911bb4e30', $q$Open Source (self-hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full DORA metrics engine","Docker deployment","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5017ecef-eeac-41d4-87fc-cca911bb4e30', $q$Managed/Cloud$q$, $q$Custom pricing$q$, $q$Custom$q$, NULL, $q$["Hosted deployment","Broader observability tooling","Vendor support"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5017ecef-eeac-41d4-87fc-cca911bb4e30', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$middlewarehq is the open-source DORA metrics project maintained by Middleware, a San Francisco startup founded by Laduram Vishnoi in late 2022 and backed by Y Combinator (W23) and an 8VC-led seed round. The project computes the four DORA metrics, deployment frequency, lead time for changes, mean time to restore, and change failure rate, directly from a team's Git and CI/CD data.$q$, $q$Released under the Apache 2.0 license and written in TypeScript, middlewarehq (also published as the dora-metrics repository) is designed to be deployed via Docker, either self-hosted by an engineering organization or run through Middleware's managed cloud offering.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5017ecef-eeac-41d4-87fc-cca911bb4e30', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform's central feature is automatic DORA metric calculation pulled from GitHub activity and CI/CD pipeline data, removing the need for engineering leaders to manually assemble delivery-performance spreadsheets. Dashboards benchmark a team's results against the standard DORA performance tiers of Elite, High, Medium, and Low.$q$, $q$Because it is open source, engineering teams with strict data-residency or security requirements can self-host the entire stack rather than sending source-control metadata to a third-party SaaS vendor, while still getting the same metric definitions used by commercial competitors.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5017ecef-eeac-41d4-87fc-cca911bb4e30', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The middlewarehq open-source project itself is completely free to self-host under the Apache 2.0 license, with Docker-based deployment and community support through GitHub. There is no license fee for running it on a company's own infrastructure.$q$, $q$Middleware, the company behind the project, also offers a broader commercial AI-based observability platform and managed hosting option for teams that would rather not operate the open-source stack themselves; pricing for that managed offering is arranged directly with the company rather than published as fixed self-serve tiers.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5017ecef-eeac-41d4-87fc-cca911bb4e30', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5017ecef-eeac-41d4-87fc-cca911bb4e30', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
