INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('99710d40-9738-45f6-85cf-44868ba8a012', $q$Is Midjourney free?$q$, $q$No, Midjourney requires a paid subscription starting at $10/month; there is no ongoing free tier for new accounts.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('99710d40-9738-45f6-85cf-44868ba8a012', $q$Do I need Discord to use Midjourney?$q$, $q$No, Midjourney also offers a standalone web app at midjourney.com in addition to its original Discord bot.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('99710d40-9738-45f6-85cf-44868ba8a012', $q$Who owns Midjourney?$q$, $q$Midjourney is an independent, self-funded company founded by David Holz; it has not taken outside venture capital.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('99710d40-9738-45f6-85cf-44868ba8a012', $q$What is the difference between Fast and Relax mode?$q$, $q$Fast mode uses paid GPU minutes for quick generation, while Relax mode is slower but unlimited on Standard tier and above.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('99710d40-9738-45f6-85cf-44868ba8a012', $q$Can I use Midjourney images commercially?$q$, $q$Yes, paid subscribers generally receive commercial usage rights, subject to Midjourney's terms of service.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('99710d40-9738-45f6-85cf-44868ba8a012', $q$What is Midjourney's newest model?$q$, $q$V8 Alpha, introduced around March 2026, with native 2K resolution and faster generation.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('99710d40-9738-45f6-85cf-44868ba8a012', $q$Concept art and illustration$q$, $q$Rapidly generate visual concepts and character or environment art.$q$, $q$Digital artists and game studios$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('99710d40-9738-45f6-85cf-44868ba8a012', $q$Marketing and ad creative generation$q$, $q$Produce campaign imagery and creative assets without a photo shoot.$q$, $q$Marketers and agencies$q$, 1);
