INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('99710d40-9738-45f6-85cf-44868ba8a012', $q$Basic$q$, $q$$10/month$q$, $q$Monthly (annual discount available)$q$, NULL, $q$["Limited Fast GPU minutes","General commercial terms"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('99710d40-9738-45f6-85cf-44868ba8a012', $q$Standard$q$, $q$$30/month$q$, $q$Monthly (annual discount available)$q$, NULL, $q$["More Fast minutes","Unlimited Relax mode"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('99710d40-9738-45f6-85cf-44868ba8a012', $q$Pro$q$, $q$$60/month$q$, $q$Monthly (annual discount available)$q$, NULL, $q$["Stealth mode","More Fast minutes"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('99710d40-9738-45f6-85cf-44868ba8a012', $q$Mega$q$, $q$$120/month$q$, $q$Monthly (annual discount available)$q$, NULL, $q$["Highest Fast minute allotment","Stealth mode","Priority generation"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('99710d40-9738-45f6-85cf-44868ba8a012', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Midjourney is a self-funded AI research lab founded by David Holz, a former NASA researcher and Leap Motion co-founder, in San Francisco in August 2021. It entered open beta in July 2022 and quickly became one of the most recognized names in generative AI image creation, known for producing distinctly polished, artistic output compared to some competitors.$q$, $q$Unlike almost every other frontier AI company, Midjourney has never taken outside venture funding, remaining profitable and independent while reportedly generating around $300 million in revenue in fiscal 2024. In August 2025 it struck a technology-licensing partnership with Meta, an unusual move for a company that has otherwise stayed independent.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('99710d40-9738-45f6-85cf-44868ba8a012', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Midjourney generates images from text prompts using proprietary diffusion models, accessible through '/imagine' commands in Discord or through its own web application at midjourney.com. Beyond initial generation, users can upscale, create variations, blend reference images and styles, and edit specific regions of an image.$q$, $q$Newer model versions have expanded capability further: V7 improved prompt coherence and image quality, while V8 Alpha, introduced around March 2026, added native 2K resolution output, sharper in-image text rendering, and roughly 5x faster generation, alongside growing support for short AI-generated video.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('99710d40-9738-45f6-85cf-44868ba8a012', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Midjourney runs on four subscription tiers with no ongoing free access for new users: Basic at $10/month, Standard at $30/month, Pro at $60/month, and Mega at $120/month. Each tier includes an allotment of 'Fast' GPU generation minutes, with unlimited slower 'Relax' mode generation included from Standard tier upward.$q$, $q$Annual billing knocks roughly 20 percent off the monthly price. Higher tiers also unlock features like stealth mode, which keeps generations private from the public community feed, and larger Fast-mode allowances for heavy commercial users such as agencies and studios.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab6e1565-807c-46d0-90ce-52da6ac62e1c', $q$Community spaces$q$, $q$Topic-based discussion feeds and member spaces.$q$, 0);
