INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab6e1565-807c-46d0-90ce-52da6ac62e1c', $q$What does Mighty Networks cost?$q$, $q$Plans start at $95/month for the Launch tier, rising to $215/month for Scale and $354/month for Growth.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab6e1565-807c-46d0-90ce-52da6ac62e1c', $q$Does Mighty Networks take a cut of sales?$q$, $q$The Launch plan charges a 2 percent transaction fee; fees are reduced or removed on higher tiers.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab6e1565-807c-46d0-90ce-52da6ac62e1c', $q$Who founded Mighty Networks?$q$, $q$Gina Bianchini, who previously co-founded Ning and earlier launched Mightybell in 2011.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab6e1565-807c-46d0-90ce-52da6ac62e1c', $q$Can I get a branded mobile app?$q$, $q$Yes, via Mighty Pro, sold as a separate custom-priced enterprise plan.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab6e1565-807c-46d0-90ce-52da6ac62e1c', $q$What can I sell on Mighty Networks?$q$, $q$Courses, memberships, events, and bundled content, all within one network.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab6e1565-807c-46d0-90ce-52da6ac62e1c', $q$How much funding has Mighty Networks raised?$q$, $q$Roughly $67.9 million total, including a $50 million Series B in 2021.$q$, 5, 'published');
