INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ab6e1565-807c-46d0-90ce-52da6ac62e1c', $q$Launch$q$, $q$$95/month$q$, $q$Monthly or annual$q$, NULL, $q$["Community, courses, and events","2% transaction fee"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ab6e1565-807c-46d0-90ce-52da6ac62e1c', $q$Scale$q$, $q$$215/month$q$, $q$Monthly or annual$q$, NULL, $q$["Higher limits","Reduced transaction fees","More automation"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ab6e1565-807c-46d0-90ce-52da6ac62e1c', $q$Growth$q$, $q$$354/month$q$, $q$Monthly or annual$q$, NULL, $q$["Highest limits","Advanced features","Minimal or no transaction fees"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ab6e1565-807c-46d0-90ce-52da6ac62e1c', $q$Mighty Pro$q$, $q$Custom pricing$q$, $q$Custom$q$, NULL, $q$["Fully branded native iOS and Android apps"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ab6e1565-807c-46d0-90ce-52da6ac62e1c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Mighty Networks is an all-in-one community and course platform founded by Gina Bianchini, who previously co-founded the social-networking platform Ning with Marc Andreessen and later launched the community app Mightybell in 2011, which evolved into Mighty Networks. The company is headquartered in Palo Alto, California, and has raised roughly $67.9 million in funding, including a $50 million Series B in 2021.$q$, $q$Rather than requiring creators to combine a separate course platform, community forum, and event tool, Mighty Networks bundles all of them, plus payments and, on higher tiers, a fully branded native mobile app, into a single product under one login.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ab6e1565-807c-46d0-90ce-52da6ac62e1c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform's community layer organizes members into topic-based spaces and discussion feeds, while its course layer supports structured content libraries and cohort-based learning. Events can be hosted live within the platform or listed for in-person gatherings, and creators can charge for memberships, one-time course purchases, or bundles.$q$, $q$Mighty Pro, available as a separate enterprise offering, produces a fully branded native iOS and Android app for a creator's network, distributed through the Apple App Store and Google Play under the creator's own name rather than Mighty Networks'.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ab6e1565-807c-46d0-90ce-52da6ac62e1c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Mighty Networks' self-serve pricing has three tiers: Launch at $95/month (with a 2 percent transaction fee on platform sales), Scale at $215/month, and Growth at $354/month, with higher tiers raising member and course limits while reducing or eliminating transaction fees. Annual billing offers a further discount.$q$, $q$Mighty Pro, the branded native app tier, is priced separately as a custom enterprise engagement arranged directly with Mighty Networks' sales team, reflecting the added cost of app-store submission, review, and maintenance for a fully white-labeled mobile app.$q$]::text[], 2);
