INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05e24cd3-962a-414e-b238-79b5d2f5477f', $q$Is Milanote free?$q$, $q$Yes, a permanent free plan exists, limited to 100 cards and 10 file uploads.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05e24cd3-962a-414e-b238-79b5d2f5477f', $q$How much does Milanote cost?$q$, $q$Paid individual plans start around $9.99/month per person billed annually.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05e24cd3-962a-414e-b238-79b5d2f5477f', $q$Who founded Milanote?$q$, $q$Milanote was founded in 2016 in Australia.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05e24cd3-962a-414e-b238-79b5d2f5477f', $q$Is Milanote good for project management?$q$, $q$It is better suited to visual planning and brainstorming than formal task and project tracking.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05e24cd3-962a-414e-b238-79b5d2f5477f', $q$Does Milanote support team collaboration?$q$, $q$Yes, with real-time collaboration, comments, and team plans for 10, 20, or 50 members.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05e24cd3-962a-414e-b238-79b5d2f5477f', $q$What is Milanote best used for?$q$, $q$Moodboards, content planning, brainstorming, and organizing creative projects.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('05e24cd3-962a-414e-b238-79b5d2f5477f', $q$Moodboard and creative brief creation$q$, $q$Collect visual inspiration and organize it into a shareable creative brief.$q$, $q$Designers and agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('05e24cd3-962a-414e-b238-79b5d2f5477f', $q$Content and editorial planning$q$, $q$Plan campaigns and content calendars visually alongside supporting assets.$q$, $q$Marketers and writers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('05e24cd3-962a-414e-b238-79b5d2f5477f', $q$Personal project and research organization$q$, $q$Organize research, notes, and inspiration for individual projects.$q$, $q$Freelancers and students$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('05e24cd3-962a-414e-b238-79b5d2f5477f', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["100 cards","10 file uploads","Unlimited boards"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('05e24cd3-962a-414e-b238-79b5d2f5477f', $q$Individual (Pro)$q$, $q$$9.99/month per person (billed annually) or $12.50/month billed monthly$q$, $q$Monthly or annual$q$, NULL, $q$["Unlimited cards","Unlimited uploads"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('05e24cd3-962a-414e-b238-79b5d2f5477f', $q$Team$q$, $q$From $49/month base$q$, $q$Monthly or annual$q$, NULL, $q$["Discounted per-seat pricing for 10, 20, or 50 member teams"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('05e24cd3-962a-414e-b238-79b5d2f5477f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Milanote is a visual notes and moodboard application founded in Australia in 2016, built around free-form drag-and-drop boards rather than linear documents, spreadsheets, or kanban columns. The company has been widely reported as bootstrapped and profitable rather than venture-funded.$q$, $q$Its central idea is the board: a blank canvas where users place notes, images, links, files, and to-do items, then arrange and connect them visually, closer to a corkboard or Pinterest board than a traditional productivity app, but with light task-tracking built in.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('05e24cd3-962a-414e-b238-79b5d2f5477f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Boards in Milanote can be nested inside other boards to build hierarchical project structures, and a library of templates covers common creative workflows like moodboards, content calendars, and storyboards. A browser extension and mobile apps make it easy to capture inspiration, images, links, screenshots, directly into a board while browsing.$q$, $q$Real-time collaboration lets teams comment and edit boards together, and content can be exported or shared outside the app for presentations and client reviews. Because boards are visual rather than list-based, Milanote tends to suit early-stage ideation and planning better than execution-focused task tracking.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('05e24cd3-962a-414e-b238-79b5d2f5477f', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Milanote's free plan has no time limit but caps usage at 100 total cards (notes, images, and links combined) and 10 file uploads, which works for small personal projects or evaluating the tool before upgrading. Paid individual plans start around $9.99/month per person when billed annually, or about $12.50/month billed monthly, and remove the card and upload caps.$q$, $q$Team pricing is available for groups of 10, 20, or 50 members at roughly a 50 percent discount versus per-seat individual pricing, along with a separate 'Upgrade your team' base plan starting around $49/month for smaller teams that don't fit the standard tiers.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f8173937-6906-403b-af26-bf7290c0ba12', $q$Distributed, scalable architecture$q$, $q$Cloud-native design that separates storage and compute for horizontal scaling.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f8173937-6906-403b-af26-bf7290c0ba12', $q$Multiple ANN index types$q$, $q$Supports HNSW, IVF, DiskANN, and other approximate-nearest-neighbor algorithms.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f8173937-6906-403b-af26-bf7290c0ba12', $q$Hybrid search$q$, $q$Combine vector similarity search with scalar and metadata filtering.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f8173937-6906-403b-af26-bf7290c0ba12', $q$Milvus Lite$q$, $q$Lightweight embedded deployment for local development inside a Python process.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f8173937-6906-403b-af26-bf7290c0ba12', $q$Kubernetes-based clustering$q$, $q$Distributed Milvus Cluster deployment for billion-scale production workloads.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f8173937-6906-403b-af26-bf7290c0ba12', $q$AI framework integrations$q$, $q$Native integration with LangChain, LlamaIndex, and Hugging Face.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f8173937-6906-403b-af26-bf7290c0ba12', $q$Zilliz Cloud managed hosting$q$, $q$Fully managed version of Milvus with free, serverless, and dedicated tiers.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f8173937-6906-403b-af26-bf7290c0ba12', $q$Open governance$q$, $q$Apache 2.0 license under the Linux Foundation's LF AI and Data Foundation.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f8173937-6906-403b-af26-bf7290c0ba12', $q$Completely free and open source for self-hosted use$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f8173937-6906-403b-af26-bf7290c0ba12', $q$Proven to scale to billions of vectors in production$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f8173937-6906-403b-af26-bf7290c0ba12', $q$Vendor-neutral governance under the Linux Foundation$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f8173937-6906-403b-af26-bf7290c0ba12', $q$Flexible deployment options from embedded and local to distributed clusters$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f8173937-6906-403b-af26-bf7290c0ba12', $q$Strong ecosystem integration with RAG and LLM tooling$q$, 4);
