INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f8173937-6906-403b-af26-bf7290c0ba12', $q$Steeper learning curve than simpler vector stores like Chroma$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f8173937-6906-403b-af26-bf7290c0ba12', $q$Feature differences exist between Milvus Lite and full cluster deployments$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f8173937-6906-403b-af26-bf7290c0ba12', $q$Competing managed alternatives like Pinecone offer simpler zero-ops onboarding$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f8173937-6906-403b-af26-bf7290c0ba12', $q$Is Milvus free?$q$, $q$Yes, the open-source, self-hosted version is completely free under the Apache 2.0 license.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f8173937-6906-403b-af26-bf7290c0ba12', $q$Who created Milvus?$q$, $q$Zilliz, a company founded in 2017 and headquartered in Redwood City, California, started developing Milvus in 2018 and open-sourced it in 2019.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f8173937-6906-403b-af26-bf7290c0ba12', $q$What is Zilliz Cloud?$q$, $q$A fully managed, hosted version of Milvus offered by Zilliz, with free, serverless, and dedicated pricing tiers.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f8173937-6906-403b-af26-bf7290c0ba12', $q$What is Milvus used for?$q$, $q$Semantic search, retrieval-augmented generation (RAG) for LLMs, recommendation systems, and image or video similarity search.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f8173937-6906-403b-af26-bf7290c0ba12', $q$How large can Milvus scale?$q$, $q$Milvus's distributed cluster architecture is designed to handle billions of vectors in production.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f8173937-6906-403b-af26-bf7290c0ba12', $q$Is Milvus governed by Zilliz alone?$q$, $q$No, Milvus was donated to the Linux Foundation's LF AI and Data Foundation in 2020, making it a vendor-neutral open-source project.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f8173937-6906-403b-af26-bf7290c0ba12', $q$Retrieval-augmented generation for LLMs$q$, $q$Store and retrieve embeddings to ground large language model responses in factual data.$q$, $q$AI and ML engineers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f8173937-6906-403b-af26-bf7290c0ba12', $q$Semantic and multimodal search$q$, $q$Search text, images, or other content by meaning rather than exact keyword match.$q$, $q$Search and data engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f8173937-6906-403b-af26-bf7290c0ba12', $q$Recommendation and similarity matching$q$, $q$Find similar items or users based on vector embeddings.$q$, $q$Product and data science teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f8173937-6906-403b-af26-bf7290c0ba12', $q$Open Source (self-hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full Milvus feature set","Apache 2.0 license","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f8173937-6906-403b-af26-bf7290c0ba12', $q$Zilliz Cloud Free Tier$q$, $q$Free$q$, $q$Monthly$q$, NULL, $q$["About 5GB storage","2.5M vCUs per month"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f8173937-6906-403b-af26-bf7290c0ba12', $q$Zilliz Cloud Serverless$q$, $q$Pay-as-you-go, about $4 per million vCUs$q$, $q$Usage-based$q$, NULL, $q$["Usage-based scaling","No infrastructure management"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f8173937-6906-403b-af26-bf7290c0ba12', $q$Zilliz Cloud Dedicated$q$, $q$From about $99/month$q$, $q$Monthly$q$, NULL, $q$["Dedicated cluster resources","Higher performance guarantees"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f8173937-6906-403b-af26-bf7290c0ba12', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Milvus is an open-source, distributed vector database built to store and search billions of high-dimensional embedding vectors, the numerical representations that power modern AI applications like semantic search and retrieval-augmented generation (RAG). Zilliz, the company that started building Milvus in 2018, open-sourced it in 2019 and donated it to the Linux Foundation's LF AI and Data Foundation in 2020, making it a vendor-neutral open-source project.$q$, $q$Zilliz was founded in 2017 and is headquartered in Redwood City, California; it has raised roughly $113 million in funding, including a $43 million Series B in 2020 and a $60 million round in 2022, and continues to lead Milvus's open-source development while selling a managed cloud version called Zilliz Cloud.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f8173937-6906-403b-af26-bf7290c0ba12', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Milvus supports multiple approximate-nearest-neighbor indexing algorithms, including HNSW, IVF, and DiskANN, and can combine vector similarity search with traditional metadata filtering for hybrid search. It is cloud-native and horizontally scalable, separating storage from compute so it can grow to handle billions of vectors in production.$q$, $q$Deployment options range from Milvus Lite, an embedded version that runs inside a Python process for local development, to a standalone Docker deployment for small workloads, up to a fully distributed Kubernetes-based cluster for large-scale production use. It integrates directly with popular AI frameworks like LangChain, LlamaIndex, and Hugging Face.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f8173937-6906-403b-af26-bf7290c0ba12', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The open-source, self-hosted version of Milvus is completely free under the Apache 2.0 license, with no usage limits beyond what a company's own infrastructure can support. This makes it a common choice for teams that want full control over their vector search infrastructure and data.$q$, $q$Zilliz Cloud, the managed hosting option, offers a free tier with roughly 5GB of storage and 2.5 million vCUs per month, a pay-as-you-go Serverless tier priced around $4 per million vCUs, and Dedicated cluster tiers starting around $99/month for teams that want guaranteed, isolated compute resources without operating Milvus themselves.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f8173937-6906-403b-af26-bf7290c0ba12', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
